"""
MKT Context Commentary — Psalms chapters 96–102
Run: python3 scripts/zc-context-psalms-96-102.py

Source data used:
- data/interlinear/psalms.json
- data/translation/draft/mediating/psalms.json (MKT text)
- data/commentary/ellicott/psalms.json (philological background)
- data/commentary/jfb/psalms.json (historical context)

Key decisions in this range:
- Pss 96-99: the YHWH-malak (LORD reigns) enthronement cluster; Sitz im Leben likely
  Feast of Tabernacles or autumnal New Year festival in the Second Temple period;
  Ps 96 = 1 Chr 16:23-33 (sung when David brought ark to Jerusalem);
  Ps 97:7 cited in Heb 1:6 ("let all God's angels worship him");
  LXX addition "from a tree/wood" in Ps 96:10 used by Justin Martyr as crucifixion prediction;
  Ps 99 triple "holy" refrain (vv 3, 5, 9) = unique trisagion structure in the Psalter;
  Ps 99:6 names Moses, Aaron, Samuel as the paradigm intercessors

- Ps 100: superscription mizmôr lĕtôdāh = specifically the todah (thanksgiving offering) psalm;
  Lev 7:12-15 backdrop; v3 textual variant lô/lōʾ; v5 ḥesed-refrain foundational

- Ps 101: royal integrity charter, king's installation pledge; "city of the LORD" v8;
  court purity code vv3-7

- Ps 102: one of seven penitential psalms (6, 32, 38, 51, 102, 130, 143);
  most descriptive superscription in the Psalter (anonymous afflicted person);
  vv 25-27 cited in Heb 1:10-12 as addressed to Christ = most direct OT→Christ application
  in the Psalter; v18 "written for a future generation" = psalm's explicit liturgical program;
  pelican/owl (v6) = birds of desolation from Lev 11:17-18 clean/unclean lists;
  structure: individual lament (vv1-11) + Zion-confidence (vv12-22) + cosmic coda (vv23-28)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-context for Psalms 96–102 — the YHWH-malak enthronement cluster (96-99),
#   the todah psalm (100), the royal integrity charter (101), and the great penitential
#   lament with its cosmic coda cited in Hebrews (102).
# CHANGE? If commentary/mkt-context/psalms.json structure changes, update load_comm/save_comm.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-context/psalms.json'));
#   [print(ch, len(d[ch])) for ch in ['96','97','98','99','100','101','102']]"

PSALMS = {
  "96": {
    "1": '<p>Psalm 96 belongs to the cluster of YHWH-malak (LORD reigns) enthronement psalms (Pss 93-99) whose Sitz im Leben was likely the great pilgrimage festivals — Tabernacles or the New Year celebration — when YHWH\'s kingship over creation and nations was liturgically proclaimed. The psalm is preserved almost verbatim in 1 Chr 16:23-33, where it was sung when David brought the ark of the covenant to Jerusalem. The ark\'s arrival triggered the proclamation: the divine king has returned to his throne-city. "Sing a new song (<em>šîr ḥādāš</em>)" — the new song formula signals fresh divine action that requires fresh praise; what God has done cannot be celebrated with old songs (also Pss 33:3; 40:3; 98:1; 144:9; 149:1; Isa 42:10; Rev 5:9; 14:3). "Let all the earth sing" — the scope of the summons is universal, not merely Israelite.</p>',
    "2": '<p>"Sing to the LORD; praise his name; announce his salvation (<em>bĕśarû</em>) day after day" — <em>bāsar</em> (to bring good news, to announce with joy) is the root of the NT <em>euangelion</em> (gospel); YHWH\'s salvation proclaimed among the nations is the OT gospel proclamation. The daily, continuous character ("day after day," <em>miyyôm lĕyôm</em>) emphasizes that the proclamation is not a one-time event but an ongoing liturgical and missional act. The threefold command in vv. 1-2 (sing, sing, announce) creates an emphatic rhetorical opening — the triple call to praise is the Psalter\'s way of expressing urgency and comprehensiveness.</p>',
    "3": '<p>"Announce his glory among the nations (<em>baggôyim</em>) and his wonderful deeds (<em>niplĕʾôtāyw</em>) among all peoples (<em>bĕkol-hāʿammîm</em>)" — the scope expands from "all the earth" (v1) to the specific category of "nations" and "all peoples" — the Gentile world beyond the covenant community. The announcement of YHWH\'s <em>kābôd</em> (glory, weighty splendor) and <em>niplāʾôt</em> (wonderful deeds/miracles) to the nations is the great missionary program of the Psalter that the NT identifies as fulfilled in the apostolic mission (Rom 15:8-12; Acts 13:47 — Isa 49:6 quoted; 1 Cor 1:18-25). Isaiah 40-66 develops the same theme: YHWH\'s salvation made known among the nations so they stream to Zion.</p>',
    "4": '<p>"For the LORD is great (<em>gādôl YHWH</em>) and most worthy of praise (<em>mĕhullāl meʾōd</em>); he is to be held in awe above every other god (<em>nôrāʾ hûʾ ʿal-kol-ʾĕlōhîm</em>)" — the incomparability formula: YHWH is not just greater than humans but greater than the divine beings themselves. "Most worthy of praise" — <em>mĕhullāl</em> from <em>hālaṭ</em>, the hallelujah root; the superlative use requires maximally extended praise. "Held in awe above every other god" — the divine council theology: YHWH presides over lesser divine beings who acknowledge his supremacy (Pss 82; 89:6-8; 97:9; Deut 32:8-9 LXX). This is not full monotheism in the later philosophical sense but functional monotheism: whatever other divine beings exist, YHWH alone is the object of worship.</p>',
    "5": '<p>"All the gods of the nations are nothing — mere idols (<em>ʾĕlîlîm</em>) — but the LORD made the heavens" — the polemical contrast between YHWH the creator and the national deities rendered as <em>ʾĕlîlîm</em>. The word <em>ʾĕlîl</em> is likely a deliberate pun on <em>ʾēl</em> (God): diminutive + pejorative, meaning "godlings, nothings, worthless ones." The LXX translates <em>ʾĕlîlîm</em> as <em>daimonia</em> (demons) — a reading Paul uses in 1 Cor 10:20-21 ("the things that pagans sacrifice are offered to demons, not to God"). The creation contrast — "the LORD made the heavens" — is the ultimate argument: the creator cannot be compared to the created. The idols are human creations worshipped as creators; YHWH is the actual creator of all.</p>',
    "6": '<p>"Honor (<em>hôd</em>) and majesty (<em>hādar</em>) surround him; strength (<em>ʿōz</em>) and beauty (<em>tipʾeret</em>) fill his sanctuary (<em>miqdāšô</em>)" — four divine attributes arranged in two pairs, each surrounding or filling the divine presence. <em>Hôd</em> (majesty, splendor, grandeur) and <em>hādar</em> (splendor, glory, beauty) — the visual magnificence of the divine presence, what the Psalter calls <em>kābôd</em> (glory). <em>ʿOz</em> (strength, might, power) and <em>tipʾeret</em> (beauty, glory, adorment) — the pairing of power and beauty is significant: the divine sanctuary is not merely powerful (as a military fortress) but beautiful (as an aesthetic achievement). Second Temple piety emphasized the beauty of the temple and its rituals as a participation in divine beauty.</p>',
    "7": '<p>"Give to the LORD, all you families of the nations (<em>mišpĕḥôt ʿammîm</em>) — give to the LORD glory and strength" — the call extends beyond Israel to the "families of nations" — the same phrase as the Abrahamic blessing formula (Gen 12:3: "all the families of the earth"; 28:14). The divine glory and strength that characterize the sanctuary (v6) are now to be "given" back — attributed and acknowledged — by the nations who witness it. The direction of cosmic liturgy: what God possesses (glory, strength), God\'s creatures are summoned to acknowledge. This acknowledgment is the cosmic worship that the Psalter envisions as the eschatological telos.</p>',
    "8": '<p>"Give to the LORD the honor his name deserves; bring your offering (<em>minḥāh</em>) and come into his courts (<em>ḥăṣērot</em>)" — the cultic action that expresses the acknowledgment: the nations are summoned to bring the <em>minḥāh</em> (grain offering, tribute offering) as vassals bring tribute to a great king. In the ANE, tribute-presentation was the formal act of acknowledging suzerainty. The "courts" of the temple (<em>ḥăṣērot</em>) — the outer courts accessible to non-Israelites, the "court of the Gentiles" of the Second Temple period — indicate that the psalm envisions Gentile access to the divine presence, not just distant acknowledgment. Isa 56:7 ("my house will be called a house of prayer for all nations") is the prophetic fulfillment of this invitation.</p>',
    "9": '<p>"Worship the LORD in the splendor of his holiness (<em>bĕhadrat-qōdeš</em>); let all the earth tremble before him" — <em>hadrat-qōdeš</em> (splendor/adornment of holiness) — worn as liturgical dress or the holy splendor that surrounds the divine presence in the sanctuary (also Pss 29:2; 110:3). The worshippers come adorned in the holiness that belongs to the sanctified cultic community; they are clothed in what they approach. "Let all the earth tremble (<em>ḥîlû</em>)" — the trembling of the earth is simultaneously the awe-response of the worshippers and the physical response of creation to divine presence (Ps 99:1; Exod 19:16-18; Isa 64:1-3). The trembling and the worship are the same act from different perspectives.</p>',
    "10": '<p>"Declare among the nations: \'The LORD reigns (<em>YHWH mālāk</em>)!\' The world is set in place and cannot be shaken; he will judge the peoples with justice" — the proclamation formula <em>YHWH mālāk</em> (the LORD reigns/has become king) is the enthronement cry, the announcement of the divine king\'s accession. The Septuagint of this verse adds a phrase not in the MT: "The LORD reigned from the tree (<em>apo tou xylou</em>, from the wood/cross)." This reading, absent from all known Hebrew manuscripts, was used by early Christian writers (Justin Martyr, Tertullian) as a direct prediction of the crucifixion — YHWH becoming king through the cross. Modern text-critical consensus rejects it as a Christian addition to the LXX, but the theological instinct is sound: the NT interprets the cross as the decisive act of divine enthronement (Phil 2:8-9; John 12:31-32).</p>',
    "11": '<p>"Let the heavens rejoice (<em>yiśmĕḥû haššāmayim</em>) and the earth be glad (<em>wĕtāgēl hāʾāreṣ</em>); let the sea and everything in it roar out (<em>yirʿam hayyām û mĕlōʾô</em>)" — the cosmic theophanic response: all of creation joins the enthronement celebration. The verbs are jussive (let them...): the psalmist calls on the cosmic elements to perform what they naturally do in response to divine action. This personification of nature in cosmic worship is not metaphor-decoration but theological statement: creation has a voice and the voice is praise (Pss 19:1-4; 148; Rom 8:19-22). The sea that roars (<em>rāʿam</em>) — the sea-chaos that was subdued at creation (Gen 1:2; Ps 93:3-4) now roars in triumphant acclamation rather than threatening rebellion.</p>',
    "12": '<p>"Let the fields exult (<em>yaʿălōz śādeh</em>) and everything in them; let all the trees of the forest shout for joy (<em>yĕrannĕnû kol-ʿăṣê yāʿar</em>)" — the agricultural and arboreal dimensions of creation join the cosmic choir. <em>ʿĀlaz</em> (to exult, to rejoice with full body engagement) — the exuberant joy of people dancing. The fields with their crops and the forest with its trees are given voices of praise. Isaiah 55:12 uses the same imagery: "the mountains and hills will burst into song before you, and all the trees of the field will clap their hands." In Second Temple Jewish thought, the natural world\'s participation in worship was a sign of the eschatological renewal (Isa 65:12-13; Rev 5:13 — "every creature in heaven and on earth and under the earth and on the sea, and all that is in them, singing").</p>',
    "13": '<p>"Before the LORD, for he is coming — coming (<em>kî bāʾ kî bāʾ</em>) to judge the earth. He will judge the world in righteousness and the peoples in his faithfulness (<em>beʾĕmûnāṯô</em>)" — the repeated "coming" (<em>bāʾ bāʾ</em>) is the climactic statement of the entire enthronement cluster: YHWH comes as judge. "Righteousness (<em>ṣedeq</em>) and faithfulness (<em>ʾĕmûnāh</em>)" — the two standards of divine judgment: right order restored and covenant reliability maintained. The coming judge is not arbitrary but committed to the covenant character that defines him. The universal scope — "the world... the peoples" — makes the coming judgment eschatological. The identical closing formula appears in Ps 98:9, creating a bracket around the enthronement collection.</p>',
  },
  "97": {
    "1": '<p>"The LORD reigns (<em>YHWH mālāk</em>); let the earth rejoice! Let all the distant coastlands be glad!" — the enthronement proclamation (same as Ps 99:1; 93:1) opens with the same formula as Ps 96:10. The "distant coastlands (<em>ʾiyyîm rabbîm</em>)" — the islands and coastlands at the edges of the known world (Isa 41:1; 42:4, 10, 12; 51:5; 66:19; Jer 31:10) — represent the remotest Gentile peoples. The joy that is commanded is responsive to the fact of divine rule: the earth doesn\'t create the reason for joy, it responds to the reality that YHWH already reigns. In ANE royal ideology, the king\'s accession was the occasion for universal celebration; Psalm 97 applies this to YHWH\'s enthronement.</p>',
    "2": '<p>"Clouds and thick darkness (<em>ʿānān waʿărāpel</em>) surround him; righteousness and justice (<em>ṣedeq ûmišpāṭ</em>) are the foundation of his throne" — two paired images: the theophanic hiddenness and the moral foundation. Clouds and darkness are the standard Sinai-theophany vocabulary (Exod 19:9, 16; 20:21; Deut 4:11; 5:22-23; 1 Kgs 8:12; Ezek 34:12; Joel 2:2; Zeph 1:15). The hidden, unapproachable divine majesty is surrounded by the same clouds that covered Sinai. "Righteousness and justice are the foundation (<em>mĕkôn</em>) of his throne" — the throne\'s stability rests not on raw power but on the moral order that defines divine rule. The same formula appears in Ps 89:14 and is the theological claim that power and justice are not in tension in YHWH\'s governance — his power is the power of right order.</p>',
    "3": '<p>"Fire goes out before him (<em>ʾēš lĕpānāyw tēlēk</em>) and consumes his enemies on every side" — the fire before YHWH is the theophanic presence-fire (Exod 13:21-22; 19:18; 24:17; Deut 4:24: "the LORD your God is a consuming fire"; Heb 12:29). The fire that guided Israel in the wilderness is now the fire of judgment that precedes the divine warrior into battle. "Consumes his enemies on every side" — the encircling judgment that leaves no escape route. The divine warrior imagery here (fire, consuming enemies) is the militarized version of the creation-theophany: the God who spoke creation into existence now advances in judgment as a warrior who burns before him.</p>',
    "4": '<p>"His lightnings (<em>bĕrāqāyw</em>) illuminate the world; the earth sees and shakes with fear" — YHWH\'s lightning as the sign of divine speech and action (Pss 18:14; 77:17-18; 144:6; Job 37:3; 38:35). In the ANE, lightning was the weapon of the storm deity — Baal\'s lightning is his "seven lightnings" in the Ugaritic texts. Psalm 97 demythologizes Baal\'s lightning as YHWH\'s own instrument: what Canaanite religion attributed to the storm god belongs to YHWH. "The earth sees and shakes (<em>watāḥēl hāʾāreṣ</em>)" — the earth\'s trembling (<em>ḥûl</em>, to tremble with birth-pangs) is both a seismic response and a metaphor of creation in the pangs of transformation before the divine presence.</p>',
    "5": '<p>"The mountains melt (<em>neharsû hārîm</em>) like wax before the LORD, before the Lord of all the earth" — the mountain-melting theophany is the most dramatic expression of divine power over the created order (Judg 5:5; Mic 1:4; Isa 64:1-3; Nah 1:5). Mountains were the ANE\'s symbol of permanence and immovability; to say that they melt before YHWH is to assert that the most permanent features of creation are subject to divine will. "Like wax" — the specificity of the wax comparison (wax melts precisely at the point of heat application, flowing away completely) emphasizes not just the power of divine presence but the completeness of the mountain\'s dissolution. "Lord of all the earth (<em>ʾădōn kol-hāʾāreṣ</em>)" — the title "Lord of the whole earth" appears in the Joshua conquest narratives (Josh 3:11, 13) in connection with the ark leading Israel across the Jordan.</p>',
    "6": '<p>"The heavens proclaim (<em>higgîdû šāmayim</em>) his righteousness, and all the peoples behold his glory" — the heavens as witnesses and proclaimers of divine character (also Ps 19:1: "the heavens declare the glory of God"). <em>Nāgad</em> (to declare, to announce, to make known) in the hiphil — the heavens actively declare what they embody and witness. "All the peoples behold his glory (<em>kābôd</em>)" — the universal witness of the divine glory; the creation-proclamation reaches all peoples, establishing a universal accountability. Paul draws on this in Rom 1:18-20: the divine glory is visible in creation to all, leaving all without excuse.</p>',
    "7": '<p>"All who worship carved images are put to shame (<em>yēbōšû</em>) — those who boast in worthless idols. All gods bow down before him (<em>hištaḥăwû-lô kol-ʾĕlōhîm</em>)" — the idol-worshipper\'s shame is the automatic consequence of the theophanic revelation: when the true God appears, all alternatives are exposed as worthless. The bowing of "all gods" — the divine council prostrating before YHWH — is the supreme expression of divine incomparability. Hebrews 1:6 cites this verse: "when he brings the firstborn into the world, he says, \'Let all God\'s angels worship him\'" — applying the prostration of the divine beings to the worship of Christ at the incarnation. The LXX reads <em>ʾĕlōhîm</em> as "angels," and Heb 1:6 follows this LXX tradition to argue for Christ\'s superiority to the angels.</p>',
    "8": '<p>"Zion heard and was glad (<em>šāmĕʿāh watiśmaḥ ṣiyyôn</em>), and the towns of Judah rejoiced because of your judgments, O LORD" — the specific covenant community\'s response to the theophanic proclamation of vv. 1-7. While "all the earth" (v1) is commanded to rejoice and the nations behold the glory (v6), Zion and the daughters of Judah have a particular, covenant-informed joy in divine judgment. For the nations, divine judgment is threatening; for Zion, which has experienced oppression at the nations\' hands, divine judgment against the wicked is liberation. "The towns of Judah (<em>bĕnôt yĕhûdāh</em>)" — literally "daughters of Judah," a personification of the surrounding cities as daughters of the mother-city Jerusalem.</p>',
    "9": '<p>"For you, LORD, are most high (<em>ʿelyôn</em>) over all the earth; you are raised far above all gods" — the incomparability statement that grounds the previous verses. <em>ʿElyôn</em> (Most High) is one of the oldest divine titles, possibly pre-Israelite (Gen 14:18-22; Num 24:16; Deut 32:8; Ps 7:17), used for the supreme deity of the Canaanite pantheon before being adopted as a title for YHWH. By using <em>ʿElyôn</em>, the psalm asserts that what the Canaanites attributed to their supreme deity rightly belongs to YHWH. "Far above all gods (<em>meʾōd naʿălêṯā ʿal-kol-ʾĕlōhîm</em>)" — the intensifier <em>meʾōd</em> (very, exceedingly) with the ascension verb: YHWH is not marginally superior but incomparably elevated above all other divine beings.</p>',
    "10": '<p>"You who love the LORD, hate evil (<em>śĭnʾû rāʿ</em>)! He guards the lives of his faithful (<em>ḥăsîdāyw</em>) and rescues them from the power of the wicked" — the ethical demand that follows from the theological proclamation. YHWH\'s kingship is not merely cosmic spectacle but moral demand: the subjects of the divine king must share the king\'s hatred of what the king hates. "Love" and "hate" in the OT covenantal language are not primarily emotional states but covenant commitments — to love YHWH is to be in covenant relationship; to hate evil is to share YHWH\'s moral orientation (Prov 8:13: "the fear of the LORD is to hate evil"). "His faithful (<em>ḥăsîdîm</em>)" — those who embody covenant loyalty, the community that reciprocates YHWH\'s <em>ḥesed</em>.</p>',
    "11": '<p>"Light (<em>ʾôr</em>) is sown (<em>zāruaʿ</em>) for the righteous and gladness for the upright in heart" — a striking agricultural metaphor: light is planted like seed, destined to spring up in due season. The image addresses the apparent contradiction of Ps 97: if YHWH reigns in fire and lightning (vv. 3-4), what becomes of the righteous who live in a dark world? The answer: light is planted for them — it is a seed that has already been sown, and its harvest is certain. The eschatological dimension: the present experience of darkness for the righteous is not the final word; the light that has been sown will produce a harvest. Second Temple Judaism developed this into the doctrine of eschatological reward.</p>',
    "12": '<p>"Rejoice in the LORD, you who are righteous, and give thanks to his holy name (<em>qodšô</em>)!" — the closing double imperative summarizes the psalm\'s movement: from theophanic vision (vv. 1-6) to polemic against idols (v7) to Zion\'s covenant joy (v8) to ethical demand (v10) to eschatological assurance (v11) to the concluding call to rejoice. The righteous are called to rejoice "in the LORD" (<em>bYHWH</em>) — not in their righteousness, not in their circumstances, but in the character and governance of YHWH himself. "His holy name" — the name that encapsulates his character and all his acts; thanksgiving to the name is thanksgiving to the person the name represents.</p>',
  },
  "98": {
    "1": '<p>Psalm 98, like 96, opens with a call to sing a "new song" (<em>šîr ḥādāš</em>) — indicating fresh divine action requiring fresh liturgical response. "For he has done wondrous things (<em>niplāʾôt</em>)" — the past tense grounds the new song in completed divine acts, not aspirations. "His right hand (<em>yĕmînô</em>) and his holy arm (<em>wĕzĕrôaʿ qodšô</em>) have gained him the victory" — the divine warrior\'s two instruments of battle: the right hand (the weapon-hand, Exod 15:6, 12; Pss 17:7; 18:35; 20:6; 44:3) and the holy arm (the symbol of divine power, Isa 40:10; 51:9; 52:10; 53:1). The "holy arm" of Isa 53:1 ("to whom has the arm of the LORD been revealed?") is the arm that brings salvation through the Servant\'s suffering — the same arm that won the victory in the Exodus now accomplishes the deeper victory of the New Exodus.</p>',
    "2": '<p>"The LORD has made his salvation (<em>yĕšûʿāṯô</em>) known and has displayed (<em>gillāh</em>) his righteousness (<em>ṣidqāṯô</em>) before the nations" — divine self-revelation in salvation history. <em>Gālāh</em> (to uncover, to reveal, to make naked) — the divine righteousness uncovered before the nations\' eyes, previously hidden. Isaiah 52:10: "the LORD will lay bare his holy arm in the sight of all the nations, and all the ends of the earth will see the salvation of our God." Both texts use the revealing arm of YHWH as the image of divine self-disclosure in salvific action. The "righteousness" shown is not condemnatory judgment but the right-order-restoring salvation — <em>ṣedāqāh</em> as saving righteousness (Isa 45:8; 51:5-6).</p>',
    "3": '<p>"He has remembered (<em>zākar</em>) his steadfast love (<em>ḥasdô</em>) and faithfulness (<em>weʾĕmûnāṯô</em>) to the house of Israel. All the ends of the earth have witnessed the salvation of our God" — divine remembering is covenantal action: YHWH "remembers" his covenant by acting on it (Gen 9:15; Exod 2:24; 6:5; Lev 26:42, 45; Ps 105:8; 106:45; 111:5; Jer 31:20; Ezek 16:60). <em>Ḥesed</em> and <em>ʾĕmûnāh</em> — the twin covenant attributes that appear together throughout the Psalter (Ps 36:5; 40:10-11; 57:3; 89:1-2, 14, 24, 33; 92:2; 100:5; 115:1; 117:2; 138:2) and in the divine self-disclosure formula of Exod 34:6-7. "All the ends of the earth" witness the covenant-keeping: what YHWH does for Israel is visible to the whole world and constitutes universal testimony.</p>',
    "4": '<p>"Shout for joy (<em>hārîʿû</em>) to the LORD, all the earth! Burst into song and sing praises (<em>pĕṣĕḥû wĕrannĕnû wĕzammērû</em>)!" — three consecutive verbs of exuberant praise: <em>rûaʿ</em> (to shout the war-cry/acclamation), <em>pāṣaḥ</em> (to burst out, to break into song), <em>rānan</em> (to give a ringing cry, to sing joyfully), <em>zāmar</em> (to make music). The accumulation of praise verbs overwhelms the grammatical structure — the praise spills over syntax. The liturgical direction "all the earth" makes the celebration universal; this is not a private Israelite festival but a cosmic event. The enthronement psalms consistently expand beyond the covenant community to include all nations in the proclamation.</p>',
    "5": '<p>"Sing praises to the LORD with the harp (<em>kinnôr</em>), with the harp and the sound of singing (<em>qôl zimrāh</em>)!" — the orchestration of worship is specified: the <em>kinnôr</em> (lyre/harp) was the primary stringed instrument of temple worship, associated with David\'s playing (1 Sam 16:23; 2 Sam 6:5; 1 Chr 25:1-3; Ps 33:2). <em>Qôl zimrāh</em> (voice of melody) — the human voice accompanying the instrument. The combination of instrumental and vocal music represents the full human acoustic offering to God. Hellenistic Judaism and early Christianity continued the harp tradition; Revelation 5:8 describes the twenty-four elders with harps as they sing the new song of the Lamb.</p>',
    "6": '<p>"With trumpets (<em>baḥăṣōṣĕrôt</em>) and the blast of the ram\'s horn (<em>qôl šôpār</em>) shout for joy before the King, the LORD!" — the two primary signaling instruments of Israelite worship are both deployed: <em>ḥăṣōṣĕrāh</em> (silver trumpet, the priestly instrument, Num 10:1-10) and <em>šôpār</em> (ram\'s horn/shofar, the ancient Israelite alarm and assembly signal). In the Second Temple period, the shofar\'s blast on Rosh Hashanah (the Jewish New Year) was understood as proclaiming YHWH\'s kingship at the new year — the liturgical connection between the shofar and divine enthronement remains in the Jewish High Holiday liturgy to this day. "Before the King, the LORD" — the royal title applied directly to YHWH.</p>',
    "7": '<p>"Let the sea thunder (<em>yirʿam hayyām</em>) with all that is in it, the world and all who live in it!" — the sea\'s thunderous voice joins the instrumental ensemble. In Ps 93:3-4, the sea\'s roaring represents the threatening chaos that YHWH subdues; here the same sea roars in acclamation and worship. The transformation of the sea from chaos-threat to praise-voice is one of the Psalter\'s great theological moves: the same power that threatened creation now magnifies its creator. "The world (<em>ṯēbēl</em>)" — not just the earth as solid ground but the inhabited world as a totality; the word emphasizes that all the world\'s inhabitants participate.</p>',
    "8": '<p>"Let the rivers clap their hands (<em>nĕhārôt yimḥăʾû-kāp</em>); let the mountains sing together (<em>yĕrannĕnû</em>) for joy!" — the rivers personified with human hands applauding and the mountains with voices singing. The rivers\' "clapping hands" is an extraordinary image: the natural phenomenon of water splashing against riverbanks is reimagined as cosmic applause. Isaiah 55:12 provides a close parallel: "the mountains and hills will burst into song before you, and all the trees of the field will clap their hands." The personified creation\'s praise is the sign of the eschatological restoration — what will happen fully when the King comes to judge anticipates and is rehearsed in the liturgy now.</p>',
    "9": '<p>"Before the LORD, for he is coming to judge the earth! He will rule the world with righteousness and the peoples with fairness (<em>mêšārîm</em>)" — the same closing formula as Ps 96:13, with "fairness" (<em>mêšārîm</em>, straightness, equity) replacing "faithfulness" (<em>ʾĕmûnāh</em>) in 96:13. The coming-to-judge is the climax of the entire enthronement celebration — not a threat but the fulfillment of the cosmic order that worship rehearses. The bracketing of the enthronement collection (Pss 96-98) with this identical formula creates a liturgical frame: the new song arises because YHWH is coming; the worship anticipates and proclaims the judgment that will set all things right.</p>',
  },
  "99": {
    "1": '<p>Psalm 99, the last of the YHWH-malak enthronement cluster, is distinguished by its triple "holy" refrain (<em>qādôš hûʾ</em>, holy is he) in vv. 3, 5, and 9 — the only psalm in the Psalter with this trisagion structure. The trisagion of Isa 6:3 ("holy, holy, holy is the LORD Almighty") echoes through this psalm, and Rev 4:8 takes up the triple "holy" in the heavenly worship. "He is enthroned above the cherubim (<em>yōšēb kĕrûbîm</em>)" — the ark-throne theology: the two golden cherubim on the ark\'s cover (<em>kappōret</em>) formed the divine throne-seat in the Most Holy Place (Exod 25:18-22; 1 Sam 4:4; 2 Sam 6:2; 2 Kgs 19:15; Isa 37:16). YHWH\'s enthronement "above the cherubim" places the entire liturgy in the context of the sanctuary\'s Most Holy Place.</p>',
    "2": '<p>"The LORD is great (<em>gādôl YHWH</em>) in Zion; he is raised high above all the peoples" — the spatial and theological center: Zion is the place where YHWH\'s greatness is declared and experienced. Unlike Ps 97\'s cosmic theophany (mountains melting, lightnings flashing), Ps 99 localizes the divine presence in the specific sanctuary of Zion. This is the tension maintained throughout the Psalter: YHWH whose glory fills the heavens and the earth has chosen to dwell in a specific place — not because his presence is limited but because his covenant-condescension makes him accessible at a specific address.</p>',
    "3": '<p>"Let them praise your great and fearsome name (<em>šimkā gādôl wĕnôrāʾ</em>) — holy is he!" — the first occurrence of the trisagion. The divine name is the object of praise because the name carries the weight of the divine character and all divine acts. <em>Nôrāʾ</em> (fearsome, awe-inspiring, terrifying) — the root <em>yārēʾ</em> (to fear, to revere): the divine name inspires reverential awe, not just intellectual acknowledgment. "Holy is he (<em>qādôš hûʾ</em>)" — <em>qādōš</em> (holy, separate, set apart, the altogether Other) is the central divine attribute that all others serve. The triple repetition of "holy" at structurally pivotal points (vv. 3, 5, 9) makes holiness the interpretive key for the entire psalm.</p>',
    "4": '<p>"The mighty king loves justice (<em>ûʿōz melek mišpāṭ ʾāhēb</em>). You have established fairness; you have carried out justice and righteousness in Jacob" — the moral character of YHWH\'s kingship. Unlike ANE monarchies where divine kingship was often associated with arbitrary power, YHWH\'s kingship is constitutively just. "Loves justice (<em>ʾāhēb mišpāṭ</em>)" — divine love directed toward the right-ordering of community relationships. Isa 61:8: "I, the LORD, love justice; I hate robbery and wrongdoing." The double naming — "justice and righteousness in Jacob" (<em>mišpāṭ ûṣĕdāqāh bĕyaʿăqōb</em>) — is the prophetic pairing that defines the ethical ideal (Isa 1:27; 5:16; 9:7; 28:17; 33:5; Amos 5:7, 24; Mic 6:8).</p>',
    "5": '<p>"Exalt the LORD our God and bow down (<em>wĕhištaḥăwû</em>) at his footstool (<em>lahădōm raglāyw</em>) — holy is he!" — the second occurrence of the trisagion. The footstool of YHWH in the Psalter refers variously to the ark (1 Chr 28:2), the temple (Ps 132:7; Isa 66:1), or the earth (Isa 66:1). To bow at the footstool is to prostrate before the enthroned king in the most submissive posture available. In ANE royal iconography, conquered enemies were depicted under the king\'s feet — prostration at the footstool was the act of subjects acknowledging sovereignty. Ps 110:1 ("until I make your enemies a footstool for your feet") uses the footstool in this conquest register; here the footstool is the place of voluntary worship.</p>',
    "6": '<p>"Moses and Aaron were among his priests; Samuel was among those who called on his name. They called out to the LORD, and he answered them" — a historical survey of Israel\'s great intercessors, deployed as evidence for YHWH\'s responsiveness to prayer. Moses and Aaron were not technically <em>kōhănîm</em> (priests from Levi\'s line through Aaron) in the narrow sense, but the psalm uses the term broadly for those who served in mediatorial roles before YHWH. Samuel was not of the Levitical priesthood but served at Shiloh (1 Sam 1-3) and was renowned as a powerful intercessor (1 Sam 7:5-9; 12:19-23; Jer 15:1). The naming of three covenant intercessors establishes that YHWH is the God who hears prayer — not a distant deity but one who answers when called upon through designated mediators.</p>',
    "7": '<p>"He spoke to them in the pillar of cloud (<em>bĕʿammûd ʿānān</em>); they kept his testimonies (<em>ʿēdōṯāyw</em>) and the law (<em>wĕḥōq</em>) he gave them" — the wilderness theophany extended through the priestly/prophetic mediation of Moses, Aaron, and Samuel. The pillar of cloud as divine speech-medium (Exod 33:9-11; Num 12:5-8; Deut 31:15) connects the divine address in the wilderness to the ongoing divine speaking through the designated mediators. "They kept his testimonies" — the <em>ʿēdôṯ</em> (testimonies, the covenant stipulations deposited in the ark — Exod 25:16, 21; 31:18) were specifically kept by the priestly guardians. The intercessors were simultaneously obedient keepers of the covenant requirements.</p>',
    "8": '<p>"LORD our God, you answered them; you were a God who forgave them (<em>ʾēl nōśēʾ lāhem</em>), yet you held them accountable (<em>nōqēm</em>) for their offenses" — the theological tension of divine governance: simultaneous forgiveness and accountability. <em>Nāśāʾ</em> (to lift, to carry, to forgive) — sin lifted and carried away; the same verb as in the scapegoat ritual (Lev 16:22: "the goat will carry on itself all their iniquities"). <em>Nāqam</em> (to avenge, to hold accountable) — the same God who forgives also ensures that sin\'s consequences are not eliminated. The verse holds both without resolving the tension into a single principle: YHWH both forgave Moses and held him accountable for striking the rock (Num 20:10-12). The NT resolution: both the forgiveness and the accountability are absorbed by Christ on the cross — he forgives because he bears the consequence.</p>',
    "9": '<p>"Exalt the LORD our God and worship at his holy mountain (<em>har qodšô</em>), for the LORD our God is holy!" — the third and final occurrence of the trisagion, now with "at his holy mountain" replacing "at his footstool" (v5). The escalating specificity — footstool (v5) → holy mountain (v9) — moves from general submission to the specific cultic location. Zion/Jerusalem as YHWH\'s holy mountain (Pss 2:6; 48:1-2; 87:1; Isa 2:2-4; Zech 8:3; Rev 21:10) is the geographic point where heaven and earth meet. The triple "holy" creates a trisagion frame for the entire psalm, making holiness the Alpha and Omega of the proclamation of YHWH\'s kingship.</p>',
  },
  "100": {
    "1": '<p>Psalm 100\'s superscription <em>mizmôr lĕtôdāh</em> (a psalm for the thank-offering) specifically designates this as the psalm accompanying the <em>tôdāh</em> (thanksgiving/thank-offering) — the particular type of peace offering (<em>šĕlāmîm</em>) presented when a person sought to thank God for specific deliverance (Lev 7:12-15; 22:29). The <em>tôdāh</em> required a public celebration, communal eating of the sacrificial meal in the temple courts, and songs of thanksgiving. Psalm 100 is thus the processional hymn sung as worshippers entered the sanctuary to present the <em>tôdāh</em> feast. "Shout for joy (<em>hārîʿû</em>) to the LORD, all the earth" — the identical opening to Ps 98:4; the universal scope means all of creation is implicitly included in the thanksgiving processional.</p>',
    "2": '<p>"Serve the LORD with joy (<em>bĕśimḥāh</em>)! Come into his presence with songs of praise (<em>birʿānānāh</em>)!" — <em>ʿābad</em> (to serve, to work, to worship) encompasses the full range of covenant service: labor, worship, and obedience are all contained in the single verb. "With joy" — the joy of covenantal service as distinct from slavish obligation; Deut 28:47-48 identifies joyless service as the spiritual condition that opens the door to covenant curse: "because you did not serve the LORD your God joyfully... you will serve the enemies the LORD sends against you." "Come into his presence (<em>bōʾû lĕpānāyw</em>)" — the approach to the divine face, the sanctuary as the place of divine face-presence (<em>pānîm</em>). "Songs of praise (<em>rĕnānāh</em>)" — the ringing, jubilant cry that accompanies the processional approach.</p>',
    "3": '<p>"Know (<em>dĕʿû</em>) that the LORD is God! He made us (<em>hûʾ ʿāśānû</em>), and we belong to him (<em>wĕlô ʾănaḥnû</em>); we are his people, the flock he tends (<em>ṣōʾn marʿîṯô</em>)" — the imperative "know" (<em>yādaʿ</em>) — covenantal knowing, not merely intellectual. Three claims are stacked: YHWH is God (his nature), he made us (his creative act), and we are his (the covenant relationship). "We belong to him (<em>lô ʾănaḥnû</em>)" — there is a textual variant: the written text (<em>kĕtîb</em>) has <em>lōʾ</em> (not: "and not ourselves we") while the traditional reading (<em>qĕrê</em>) has <em>lô</em> (to him). The <em>qĕrê</em> is almost universally followed. The shepherd metaphor ("flock he tends") connects to the entire OT shepherd-king tradition climaxing in Jesus\'s "I am the good shepherd" (John 10:14).</p>',
    "4": '<p>"Enter his gates (<em>šĕʿārāyw</em>) with thanksgiving (<em>bĕtôdāh</em>) and his courts (<em>ḥăṣērōṯāyw</em>) with praise (<em>bĕtĕhillāh</em>)! Thank him and bless his name!" — the processional instructions for the <em>tôdāh</em> offering: the worshipper moves inward through the gates (outer wall) and courts (the open areas between gate and sanctuary), each threshold marked by the intensification of praise. The gate → courts → sanctuary movement mirrors the increasing holiness of concentric spaces in the Israelite sanctuary. "Bless his name (<em>bārĕkû šĕmô</em>)" — divine blessing directed toward the name; the name is the target of blessing as it is the source of blessing (Num 6:24-27; Ps 103:1-2; 145:1-2). The name contains and represents all that God is and has done.</p>',
    "5": '<p>"For the LORD is good (<em>kî-ṭôb YHWH</em>); his steadfast love (<em>ḥasdô</em>) endures forever (<em>lĕʿôlām</em>), and his faithfulness (<em>weʾĕmûnāṯô</em>) reaches to every generation" — the theological foundation of the entire processional: the <em>tôdāh</em> is grounded in divine character, not merely in specific past acts. The three divine attributes — goodness, <em>ḥesed</em>, and faithfulness — span time (forever, every generation) in a way that specific acts do not. <em>Ḥesed</em> enduring "forever (<em>lĕʿôlām</em>)" is the great refrain of Ps 136, where it punctuates 26 specific historical acts. Here it is stated without the specific acts — divine covenant loyalty is the permanent backdrop against which all specific deliverances occur.</p>',
  },
  "101": {
    "1": '<p>Psalm 101 is one of the most distinctly royal psalms — a first-person declaration of governance principles by the king. Its Sitz im Leben may be the king\'s installation ceremony, a periodic covenant renewal, or a regular royal commitment. "Of David" (superscription) — the Davidic attribution makes the king the speaker throughout. "I will sing (<em>ʾāšîrāh</em>) of steadfast love (<em>ḥesed</em>) and justice (<em>ûmišpāṭ</em>); to you, LORD, I will make music (<em>ʾăzammĕrāh</em>)" — the king declares his governing values before declaring them as behavioral commitments. <em>Ḥesed</em> and <em>mišpāṭ</em> are the paired covenant attributes (Pss 33:5; 36:5-6; 89:14; 97:2; Isa 16:5) that define the ideal governance. The king who sings of these before YHWH places his governance within the divine governance, not as an independent program.</p>',
    "2": '<p>"I will conduct myself (<em>ʾaśkîlāh</em>) with wisdom and integrity (<em>bĕdereḵ tāmîm</em>). O when will you come to me (<em>māṯay tābôʾ ʾēlāy</em>)?  I will walk (<em>ʾeṯhallēk</em>) with a blameless heart (<em>bĕtōm-lĕbāb</em>) within my own house (<em>bĕqereb bêṯî</em>)" — the personal character commitments before moving to governance. <em>Śākal</em> (to be wise, to act prudently, to prosper through wisdom) — the wisdom-governance of the Solomonic ideal (1 Kgs 3:12; 10:24). "O when will you come to me?" — a parenthetical yearning for divine presence; the king cannot govern wisely without divine accompaniment. This honest petition interrupts the declarations of commitment, acknowledging that the commitment requires ongoing divine support. "Blameless heart (<em>tōm-lēb</em>)" — integrity as inner orientation, not just external performance; the same term as Job\'s integrity.</p>',
    "3": '<p>"I will not place (<em>lōʾ-ʾāšîṯ</em>) anything vile (<em>dĕbar-bĕliyaʿal</em>) before my eyes. I despise the conduct (<em>ʿăśôṯ-sĕṭîm</em>) of those who fall away; it will have no hold on me (<em>lōʾ yidbaṭ-bî</em>)" — the king\'s visual commitment: he will not place <em>bĕliyaʿal</em> (worthlessness, wickedness, what is without value/Belial) before his eyes. In the ANE royal court, the king was surrounded by petitioners, counselors, entertainers, and symbols of power — the temptation to fill the visual and psychological space with what is vile (pornographic, violent, or idolatrous) was real and documented in the royal courts of the ancient world. <em>Sĕṭîm</em> (those who turn aside, apostates) — the falling-away from covenant commitment that the king explicitly repudiates.</p>',
    "4": '<p>"I will have nothing to do with a crooked heart (<em>lēbāb ʿiqqēš</em>); I will have no part in evil" — the inner and outer commitments reinforce each other: the crooked heart leads to evil action; rejecting the crooked person is protecting oneself from the influence that corrupts the inner life. <em>ʿIqqēš</em> (crooked, perverse, distorted) — the opposite of the straight path of wisdom (Prov 2:15; 8:8; 11:20; 17:20; 19:1; 28:6). The covenant community requires mutual integrity — the king who keeps crooked people close to him will be corrupted by their crookedness, no matter how pure his own intention.</p>',
    "5": '<p>"Whoever slanders (<em>mĕlāšĕnî</em>) his neighbor in private (<em>bĕsēṯer</em>), him I will silence (<em>ʾaṣmîṯennû</em>). The proud-eyed (<em>gĕbah-ʿênayim</em>) and the arrogant-hearted (<em>ûrĕḥab lēbāb</em>) I will not tolerate" — slander in private (<em>bĕsēṯer</em>) is more dangerous than open accusation because it cannot be easily refuted. The king\'s court was the setting in which political slander and false accusations were deployed to advance careers and destroy rivals; the king commits to silence (<em>ṣāmaṯ</em>, to destroy, to cut off) those who use such weapons. "Proud-eyed" — the eye as the organ of arrogance; haughty eyes (<em>ʿênayim rāmôṯ</em>) are the first item in Prov 6:16-19\'s list of seven things YHWH hates.</p>',
    "6": '<p>"My eyes will be on (<em>ʿênay bĕ</em>) the faithful people of the land (<em>neʾĕmĕnê-ʾāreṣ</em>), that they may live with me; only those who walk blamelessly (<em>bĕdereḵ tāmîm</em>) will serve in my presence" — the positive counterpart to vv. 3-5\'s exclusions: the king actively seeks the faithful. <em>Neʾĕmān</em> (faithful, trustworthy, reliable) from <em>ʾāman</em> (to be firm, to be reliable, to believe). "That they may live with me" — royal patronage and residential proximity in the palace were marks of favor and trust (cf. 1 Sam 18:2; 2 Sam 9:7, 13 — Mephibosheth ate at David\'s table). "Walk blamelessly (<em>dereḵ tāmîm</em>)" — the same integrity-walk of v2; the king selects for servants whose character mirrors his own commitment.</p>',
    "7": '<p>"No one who practices deceit (<em>ʿōśēh rĕmiyyāh</em>) will live in my house; no one who tells lies (<em>dōbēr šĕqārîm</em>) will remain in my presence (<em>lĕnegel ʿênāy</em>)" — the court purity code is extended into the palace itself. <em>Rĕmiyyāh</em> (deceit, slackness, treachery) — the slack bow of Ps 78:57 and the deceitful tongue of Prov 12:17; 14:5. "In my presence (<em>lĕnegel ʿênāy</em>)" — literally "before my eyes"; the king\'s gaze is the test. This is both a policy statement about royal court governance and a typological template for YHWH\'s own court: in the divine court, no deceit, no lying (Rev 21:27; 22:15). The ideal Davidic governance points forward to the King who will govern a fully purified court.</p>',
    "8": '<p>"Each morning (<em>labbĕqārîm</em>) I will silence all the wicked in the land, cutting off (<em>lĕhakrît</em>) every evildoer from the city of the LORD (<em>mêʿîr YHWH</em>)" — the daily, regular administration of justice. "Each morning" — the judicial session in the ancient Israelite city was held in the morning at the city gate (Jer 21:12: "administer justice every morning"; 2 Sam 15:2; Ruth 4:1-2). <em>Lĕhakrît</em> (to cut off, to eliminate) — the covenant penalty for the most serious offenses (Exod 12:15, 19; Lev 7:20-21; 18:29; 20:17-18). "The city of the LORD (<em>ʿîr YHWH</em>)" — Jerusalem as the city that belongs to YHWH; the king\'s justice is administration of the divine king\'s city on behalf of the divine king. The king\'s ultimate accountability is to the LORD whose city he governs.</p>',
  },
  "102": {
    "1": '<p>Psalm 102 carries the Psalter\'s most descriptive superscription: "A prayer of an afflicted person when he is faint and pours out his anguish before the LORD" — anonymous, generic, describing a type of situation rather than naming a person or historical moment. This intentional anonymity makes the psalm universally applicable; any afflicted person can enter the prayer. Psalm 102 is one of the seven traditional penitential psalms (Pss 6, 32, 38, 51, 102, 130, 143), used in Christian liturgy since the early church for Ash Wednesday and penitential seasons. "Hear my prayer (<em>šimʿāh ṯĕpillāṯî</em>); let my cry (<em>šawʿāṯî</em>) reach you!" — the double petition combines <em>tĕpillāh</em> (prayer, the structured address) and <em>šawʿāh</em> (cry, the urgent, unstructured outcry). Both registers of speech are sent to YHWH: the composed prayer and the anguished cry.</p>',
    "2": '<p>"Do not hide your face (<em>ʾal-tasṯēr pānêkā</em>) from me when I am in trouble! Lean down (<em>haṭṭēh-ʾēlāy ʾoznĕkā</em>) and listen; answer me quickly (<em>mĕhēr ʿănēnî</em>) when I call!" — three negative and positive petitions: do not hide, lean down, answer quickly. The hidden face of God is the most severe expression of divine absence in the Psalter (Pss 13:1; 22:24; 44:24; 69:17; 143:7; cf. Isa 54:8; 59:2). "Lean down" — the auditory anthropomorphism: YHWH bending his ear toward the sufferer, inclining from the divine height to catch the human whisper (Pss 17:6; 31:2; 71:2; 86:1; 88:2). "Answer me quickly" — the urgency of the situation makes delay unacceptable; this is an emergency prayer, not a leisurely petition.</p>',
    "3": '<p>"For my days are vanishing like smoke (<em>kāʿāšān kālû yāmāy</em>), and my bones burn (<em>nôqĕdû</em>) like a blazing hearth" — the smoke image: not the slow dissipation of vapor but the sudden disappearance of smoke when the fire dies — here today, gone in seconds. "My bones burn" — <em>nāqad</em> (to kindle, to burn as a firebrand) — the sensation of fever burning in the bones (also Ps 22:14-15: "my bones are out of joint... my strength is dried up like a potsherd"). The combination of vanishing life and burning physical suffering creates the opening image of complete crisis: the person is being consumed from without (time vanishing like smoke) and from within (bones burning).</p>',
    "4": '<p>"My heart is crushed like grass (<em>hûkāh kāʿēśeb libbî</em>) and has dried up; I have even forgotten to eat" — <em>hākāh</em> (to be struck, to be beaten down) — the heart struck down like grass in the heat, wilting and drying immediately after. "Forgotten to eat" — the loss of appetite as the most basic indicator of severe depression and distress; in biblical anthropology, to forget the basic life-sustaining act of eating signals the complete displacement of the person\'s attention by their crisis (1 Sam 1:7: Hannah "wept and did not eat" in her anguish; 2 Sam 3:35; 12:16-17; 1 Kgs 21:4-5 — Ahab on his bed refusing to eat). The forgetting of food is the forgetting of life-care itself.</p>',
    "5": '<p>"From my constant groaning (<em>miqqôl ʾanḥāṯî</em>) I am reduced to skin and bones (<em>dābĕqāh ʿaṣmî lĭśrî</em>)" — <em>ʾanḥāh</em> (groaning, sighing) — the involuntary sound of sustained suffering, repeated continuously. The physical result: bones clinging to flesh (<em>dābaq ʿeṣem lĕ-bāśār</em>). <em>Dābaq</em> (to cling, to adhere, to stick) — the word for the covenant-loyalty of Ruth clinging to Naomi (Ruth 1:14) and of marriage-union in Gen 2:24; here the bones "cling" to the skin because the muscle and fat between them have wasted away. The extreme bodily depletion creates the picture of someone at the edge of physical existence — starvation-level wasting from grief, illness, or fasting.</p>',
    "6": '<p>"I am like a pelican (<em>qaʾat</em>) of the desert, like an owl (<em>kôs</em>) haunting the ruins" — the two birds named here — <em>qaʾat</em> (pelican or a large desert bird) and <em>kôs</em> (owl or a bird of desolate places) — appear in the Levitical clean/unclean lists (Lev 11:17-18; Deut 14:16-17) and in the prophets as symbols of desolation (Isa 34:11: "the desert owl and screech owl will possess it; the great owl and the raven will nest there"; Zeph 2:14). By comparing himself to these birds of wilderness and ruins, the psalmist places himself in the category of the abandoned place — the destroyed city, the depopulated wasteland. He is not in the community of the living but in the company of birds that haunt the dead places.</p>',
    "7": '<p>"I cannot sleep (<em>šāqadtî</em>); I am like a solitary bird (<em>ṣippôr bōdēd</em>) stranded on a rooftop" — <em>šāqad</em> (to be awake, to watch, to lie awake in vigilance or anxiety) — the sleepless vigil of the distressed person. The solitary bird on a rooftop is one of the Psalter\'s most intimate images of isolation: a single bird, separated from its flock, on an exposed surface. In a culture where the extended family and covenant community were the structures of human identity and support, radical aloneness was experienced as an existential crisis rather than simply a preference. The rooftop bird is exposed to predators, to weather, to cold — unprotected by the usual social shelter.</p>',
    "8": '<p>"My enemies insult me all day long; those who deride me invoke my name as a curse (<em>nišbĕʿû bî</em>)" — the social persecution adds external pressure to the internal suffering. "Invoke my name as a curse" — using someone\'s name in an oath formula so that the curse falls on them (cf. Gen 48:20: "God make you like Ephraim and Manasseh" — using names as blessing formulas; here the names are used as curse formulas). To be the person by whose name one curses another is to be publicly designated as a negative exemplar — the embodiment of misfortune, the paradigmatic sufferer whose condition one prays to avoid.</p>',
    "9": '<p>"For I eat ashes (<em>ʾēper</em>) instead of bread and mix my tears (<em>bĕmôsĕkay</em>) into what I drink" — ashes as food and tears as drink are the inverted covenant meals. Covenant feasting (Deut 8:10; Pss 22:26; 34:8; 63:5) gives way to ashes and tears — the substances of mourning. <em>ʾEper</em> (ashes, dust) — the substance put on the head in mourning (2 Sam 13:19; Esth 4:1-3; Jer 6:26; Lam 3:16); here it becomes the food itself, the ultimate self-abasement. "Mix tears into drink" — the mixing of tears with liquid drink (cf. Ps 80:5: "You have fed them with the bread of tears and made them drink tears in full measure") describes grief so pervasive that normal nourishment is contaminated by mourning.</p>',
    "10": '<p>"Because of your fury (<em>zaaʿapmĕkā</em>) and wrath (<em>wĕqiṣpĕkā</em>); for you have lifted me up only to hurl me down (<em>kî-nĕśāʾtanî wattĕšlîkēnî</em>)" — the psalmist attributes the suffering to divine agency, as in Ps 38:2-3. This is not masochism but honest theological realism: the covenant theology of the OT holds that YHWH governs history, including its catastrophic moments. "Lifted me up to hurl me down" — the metaphor of divine-warrior handling of the defeated enemy (Isa 22:17-18: "the LORD will hurl you away... he will roll you up tightly like a ball and throw you"); but here it is applied to the psalmist himself, the divine friend become divine enemy. This is Job\'s experience: "your hands shaped and made me... yet now you hurl me to destruction" (Job 10:8-9).</p>',
    "11": '<p>"My days are like a fading shadow at evening (<em>kĕṣēl nāṭûy</em>); I am withering like grass (<em>kāʿēśeb ʾîbāš</em>)" — the closing images of the individual lament section: the lengthening shadow of evening (the shadow that stretches longest before it disappears in darkness) and the withering grass (Pss 37:2; 90:5-6; 103:15-16; Isa 40:6-8). Both images capture the brevity and fragility of individual life. "A fading shadow" — the Hebrew <em>nāṭāh</em> can mean "stretched out" or "extended" — the shadow of evening is stretched far but vanishes completely at night. The individual lament ends at the nadir of abandonment and imminent death — the pivot in v12 is therefore all the more dramatic.</p>',
    "12": '<p>"But you, LORD, are enthroned (<em>ʾattāh YHWH lĕʿôlām tēšēb</em>) forever; your name endures throughout every generation" — the dramatic pivot: from the psalmist\'s fading shadow (v11) to the eternal enthronement of YHWH. The contrast is absolute: individual transience vs. divine permanence; the person\'s days dissolving vs. YHWH\'s name enduring through every generation. This is the structure of Ps 90:1-6 at the macro level: human beings pass like grass while "you are God from everlasting to everlasting." The enthroned, permanent God is the basis for the petition that follows: precisely because YHWH endures when the psalmist does not, YHWH can intervene in a way the psalmist cannot for himself.</p>',
    "13": '<p>"You will rise up (<em>ʾattāh tāqûm</em>) and have mercy on Zion; the time (<em>ʿēṯ</em>) to show her favor has come — the appointed hour (<em>môʿēd</em>) is here" — the transition from individual lament to national hope: the psalmist\'s personal crisis is contextualized within the restoration of Zion. The "appointed time (<em>môʿēd</em>)" — the cultic appointment (Lev 23:2; Num 9:2-3; Ps 75:2; Hab 2:3) — the moment that YHWH himself has set for Zion\'s restoration. "You will rise up" — <em>qûm</em> in the imperfect: it is as certain as if it has already happened. The individual\'s confidence in personal mercy (v1-11) widens into confidence in corporate restoration (vv. 12-22). The exile community\'s prayer for Zion and the individual\'s prayer for mercy are the same prayer at different scales.</p>',
    "14": '<p>"For your servants hold her very stones dear (<em>kî-rāṣû ʿăbādêkā ʾeṯ-ʾăbānêhā</em>) and take pity even on her dust" — the rubble of the destroyed Jerusalem (Lam 4:1: "how the gold has become dim; how the pure gold has changed! The sacred stones lie scattered at every street corner") is still the object of love for the exiles. The stones of the destroyed temple are more precious than any other material because they are the stones of YHWH\'s house. Nehemiah 2:17; 4:2 show the same emotional investment in the rubble of Jerusalem\'s walls. The covenant love for Zion extends even to its ruins — and that love is the basis for the petition that YHWH, who cares even more than his servants, will surely restore her.</p>',
    "15": '<p>"The nations will stand in awe (<em>yîrĕʾû gôyim</em>) of the name of the LORD, and all the kings of the earth will reverence your glory (<em>kābôdekā</em>)" — the restoration of Zion will produce the universal recognition of YHWH that the enthronement psalms called for (Pss 96:3; 97:6; 98:2-3). The nations\' awe and the kings\' reverence are the result of witnessing what YHWH does for his people — divine faithfulness to the covenant community is the instrument of universal mission. Isaiah develops this theme extensively: "Nations will come to your light, and kings to the brightness of your dawn" (Isa 60:3); "kings will shut their mouths because of him, for what they were not told, they will see" (Isa 52:15).</p>',
    "16": '<p>"For the LORD will rebuild (<em>bānāh YHWH</em>) Zion and reveal himself (<em>wĕnirʾāh</em>) in his glory" — the rebuilding of Zion is the divine self-revelation. YHWH does not merely commission the rebuilding but is himself present in it — the construction is a theophany. This confidence grounds the restoration prophecy of Second Isaiah: "Comfort, comfort my people... Speak tenderly to Jerusalem, and proclaim to her that her hard service has been completed" (Isa 40:1-2). The verb <em>bānāh</em> (to build) applied to YHWH as builder of Zion echoes Ps 127:1: "Unless the LORD builds the house, the builders labor in vain" — human rebuilding (Nehemiah, Ezra, Zerubbabel) is only effective because YHWH is doing the building.</p>',
    "17": '<p>"He listens (<em>pānāh</em>) to the prayer of the helpless (<em>šĕpî-ḥenāpî</em>) and does not ignore (<em>lōʾ-bāzāh</em>) their cry" — the helpless (<em>ʿārûr</em>) — the destitute, the stripped-bare, the person with no resources. YHWH\'s attention to the destitute is the covenant commitment that runs through the Psalter\'s lament tradition (Pss 9:12; 10:17-18; 22:24; 34:6; 69:33; 72:12-14; 107:41; 113:7-9; Isa 25:4; 57:15). "Does not ignore (<em>lōʾ bāzāh</em>, does not despise)" — the same verb as Ps 22:24: "he has not despised or scorned the suffering of the afflicted one; he has not hidden his face from him but has listened to his cry." The divine attentiveness to the desperate person is the covenant guarantee that creates the confidence to pray in the first place.</p>',
    "18": '<p>"Let this be written down (<em>yikkātēb zōʾṯ</em>) for a future generation (<em>lĕdôr ʾaḥărôn</em>), so that a people not yet born (<em>ʿam yibbārēʾ</em>) will praise the LORD" — the psalm\'s explicit liturgical self-awareness: it is composed not only for the present community but intentionally written for future generations. This parallels Ps 78:4-7\'s intergenerational transmission program — the covenant memory must reach those not yet born. "A people not yet born (<em>ʿam yibbārēʾ</em>)" — literally "a people that will be created"; the future community is a divine creation, not merely a biological continuation. This verse is one of the most direct statements of why the psalms were written and preserved: they are instruments for the praise of unborn generations.</p>',
    "19": '<p>"That the LORD looked down (<em>kî-hišqîp</em>) from his holy height; from heaven (<em>miššāmayim</em>) he gazed upon the earth" — the divine downward gaze from the cosmic height to the earthly situation of the prisoner (v20). <em>Šāqap</em> (to look down, to look out, to gaze from above) — the same verb used for YHWH looking down on the earth in Gen 18:16; 19:28; and for the divine gaze through the lattice of Isa 14:16; Song 2:9. "His holy height (<em>mimmĕrôm qodšô</em>)" — the "high and holy place" where YHWH dwells (Isa 57:15: "I live in a high and holy place, but also with the one who is contrite and lowly in spirit"). The height from which YHWH looks is the height from which he also descends to the low.</p>',
    "20": '<p>"To hear the groaning (<em>šōmĕʿ ʾanqaṯ āsîr</em>) of the prisoner and release those condemned to death" — the divine gaze from the height (v19) is not passive observation but purposeful attention leading to action. <em>ʾAsîr</em> (prisoner, captive) — the exiles in Babylon are the prisoners; <em>bĕnê ṯĕmûṯāh</em> (condemned to die, "children of death") — those marked for death by their circumstances. The verbal sequence — gazed (v19) → to hear (v20) → to release — is the anatomy of divine rescue: perception leads to hearing leads to liberation. Psalm 146:7 uses similar language: "The LORD sets prisoners free"; and Isa 61:1 (cited by Jesus in Luke 4:18): "The Spirit of the LORD... has sent me to proclaim freedom for the captives."</p>',
    "21": '<p>"So that the name of the LORD would be proclaimed in Zion and his praise sung in Jerusalem" — the telos of the divine rescue: not merely the prisoners\' relief but the worship of YHWH in Zion. The rescue is instrumental to the worship: YHWH acts in order to be praised. This is the same teleological claim as the Exodus: YHWH delivered Israel from Egypt "so that my name might be proclaimed in all the earth" (Exod 9:16; cf. Rom 9:17). The gathering of the redeemed in Zion for worship is the eschatological goal of all divine salvific action — what the book of Revelation depicts in its vision of the new Jerusalem (Rev 7:9-17; 21:22-22:5).</p>',
    "22": '<p>"When peoples and kingdoms assemble together to worship the LORD" — the universal scope of the final praise community: not merely Israel restored but peoples (<em>ʿammîm</em>) and kingdoms (<em>mĕlākôt</em>) gathered together. This is the Abrahamic vision of Gen 12:3 ("all peoples on earth will be blessed through you") realized: the rescue of Zion becomes the magnet that draws all nations. Isaiah 2:2-4 provides the fullest development: "All nations will stream to it [the mountain of the LORD]. Many peoples will come and say, \'Come, let us go up to the mountain of the LORD.\'"; cf. Mic 4:1-3; Zech 8:20-23; Matt 28:18-20.</p>',
    "23": '<p>"He has sapped my strength in midcourse (<em>ʿinnāh baddereḵ kōḥî</em>); he has shortened my days" — the return to individual lament after the Zion-confidence section (vv. 12-22). The sudden re-collapse into personal crisis creates the psalm\'s most striking structural feature: having envisioned the universal gathering at Zion, the psalmist is confronted again with his own imminent death. "In midcourse (<em>baddereḵ</em>)" — literally "in the way," cut off while still on the road, before completing the journey. The midcourse death is the one that seems most unjust: not dying at old age after a full life but being cut down before arrival.</p>',
    "24": '<p>"I said, \'O my God, do not take me away (<em>al-taʿălēnî</em>) in the middle of my life (<em>baḥăṣî yāmāy</em>) — you whose years go on through all generations (<em>bĕdôr dōrîm šĕnôṯêkā</em>)!\'" — the contrast is stark: divine years extending through all generations vs. the psalmist\'s life cut at its midpoint. The appeal uses the contrast as an argument: YHWH who transcends time can easily extend the psalmist\'s time. Hezekiah\'s prayer (Isa 38:10-20; 2 Kgs 20:1-6) is structurally similar: "In the prime of my life must I go through the gates of death?" The desperate prayer not to be taken in midlife is universal — the psalm generalizes Hezekiah\'s individual crisis into a reusable liturgical form.</p>',
    "25": '<p>"Long ago you laid the earth\'s foundation (<em>lĕpānîm hāʾāreṣ yāsadtā</em>), and the heavens are the handiwork you shaped (<em>ûmaʿăśēh yādêkā šāmāyim</em>)" — the cosmic perspective that reframes the individual crisis: the God being petitioned is the creator of heaven and earth. The creation claim is the argument: the one who created the cosmos can surely sustain one person\'s life. The same appeal is made by Second Isaiah: "Do you not know? Have you not heard? The LORD is the everlasting God, the Creator of the ends of the earth. He will not grow tired or weary" (Isa 40:28). Hebrews 1:10-12 cites vv. 25-27 as addressed to Christ — "in the beginning, Lord, you laid the foundations of the earth" — applying the creation claim to the pre-incarnate Son.</p>',
    "26": '<p>"They will perish (<em>hēmmāh yōʾbēdû</em>), but you will endure (<em>wĕʾattāh taʿămōd</em>); they will all wear out like old clothes (<em>kullām kabbegED yiblû</em>). You will roll them up like a garment (<em>kalbûš taḥălîpēm</em>) and they will be changed (<em>wĕyaḥălipû</em>)" — the wearing-out and changing of the heavens is expressed through the clothing metaphor: the cosmos is garments worn by the divine wearer, and like all garments they will eventually be discarded and changed. The clothing-of-creation metaphor appears in Isa 51:6 ("lift up your eyes to the heavens, look at the earth beneath; the heavens will vanish like smoke, the earth will wear out like a garment"). Hebrews 1:11-12 applies this precisely to Christ: the Son will "roll up" the heavens like a garment — indicating that the eschatological new creation is the Son\'s active doing.</p>',
    "27": '<p>"But you are ever the same (<em>wĕʾattāh-hûʾ</em>), and your years will never end" — <em>ʾattāh-hûʾ</em> (you are he, you are the same, you remain yourself) — the divine self-identity as the ultimate ground of stability. When everything else changes — the heavens and earth worn out and replaced — YHWH remains <em>hûʾ</em> (the same he, the consistent self). Isa 43:10, 13: "so that you may know and believe me and understand that I am he (<em>ʾĂnî hûʾ</em>). Before me no god was formed, nor will there be one after me." John 8:58 ("before Abraham was born, I am") and the Revelation\'s "the one who is and who was and who is to come" (Rev 1:4, 8) develop this divine self-consistency into the Christ who is "the same yesterday and today and forever" (Heb 13:8).</p>',
    "28": '<p>"The children of your servants (<em>bĕnê-ʿăbādêkā</em>) will live in safety; their descendants (<em>wĕzarʿām</em>) will be established (<em>yikkônān</em>) in your presence" — the psalm closes not with the individual\'s rescue but with the covenant community\'s multigenerational security. The "children of your servants" are the next generation of covenant people; their establishment in the divine presence is the promise of covenant continuity. "Established (<em>kûn</em>) in your presence" — <em>kûn</em> (to be established, to be made firm, to be prepared) used for the lasting establishment of the covenant people. The individual who feared midcourse death (v23) closes the psalm with confidence in the permanence of the covenant community beyond any individual life — the personal transience is absorbed into the community\'s continuity, and the community\'s continuity is guaranteed by YHWH\'s own eternal selfhood (v27).</p>',
  },
}

def main():
    existing = load_comm('mkt-context', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-context', 'psalms', existing)
